@Injectable()
export class LearningService implements OnApplicationBootstrap {
  constructor(
    @InjectRepository(CourseOrmEntity)
    private readonly courseRepo: Repository<CourseOrmEntity>,
    @InjectRepository(UserProgressOrmEntity)
    private readonly progressRepo: Repository<UserProgressOrmEntity>,
    @InjectRepository(QuizResultOrmEntity)
    private readonly quizResultRepo: Repository<QuizResultOrmEntity>,
  ) {}

  async onApplicationBootstrap() {
    const count = await this.courseRepo.count();
    if (count === 0) {
      const courses = SEED_COURSES.map(c => this.courseRepo.create({ id: uuidv4(), ...c }));
      await this.courseRepo.save(courses);
    }
    await this.ensureQuizzes();
    await this.ensureLessons();
  }

  private async ensureQuizzes() {
    const courses = await this.courseRepo.find();
    const updates = courses.filter(c => !c.quiz).map(c => {
      const quiz = SEED_QUIZZES[c.title];
      return quiz ? this.courseRepo.save({ ...c, quiz }) : null;
    }).filter(Boolean);
    if (updates.length) await Promise.all(updates);
  }

  private async ensureLessons() {
    const courses = await this.courseRepo.find();
    const updates = courses.filter(c => !c.lessons).map(c => {
      const lessons = COURSE_LESSONS[c.title];
      return lessons ? this.courseRepo.save({ ...c, lessons }) : null;
    }).filter(Boolean);
    if (updates.length) await Promise.all(updates);
  }

  async getCourses() {
    return this.courseRepo.find({ order: { createdAt: 'ASC' } });
  }

  async getCourse(id: string) {
    const course = await this.courseRepo.findOneBy({ id });
    if (!course) throw new NotFoundException('Curso no encontrado');
    return course;
  }

  async getQuiz(courseId: string) {
    const course = await this.courseRepo.findOneBy({ id: courseId });
    if (!course) throw new NotFoundException('Curso no encontrado');
    if (!course.quiz) throw new NotFoundException('Este curso no tiene quiz disponible');
    return course.quiz;
  }

  async getUserProgress(userId: string) {
    return this.progressRepo.find({ where: { userId }, relations: ['course'] });
  }

  async completeLesson(userId: string, courseId: string, lessonIndex: number) {
    const course = await this.courseRepo.findOneBy({ id: courseId });
    if (!course) throw new NotFoundException('Curso no encontrado');

    let record = await this.progressRepo.findOneBy({ userId, courseId });
    if (!record) {
      record = this.progressRepo.create({ id: uuidv4(), userId, courseId, progress: 0, completedLessons: [] });
    }

    if (!record.completedLessons.includes(lessonIndex)) {
      record.completedLessons = [...record.completedLessons, lessonIndex];
    }

    const totalLessons = (course.lessons ?? []).length || 1;
    record.progress = Math.round((record.completedLessons.length / totalLessons) * 100);

    return this.progressRepo.save(record);
  }

  async updateProgress(userId: string, courseId: string, dto: UpdateProgressDto) {
    let record = await this.progressRepo.findOneBy({ userId, courseId });
    if (!record) {
      const course = await this.courseRepo.findOneBy({ id: courseId });
      if (!course) throw new NotFoundException('Curso no encontrado');
      record = this.progressRepo.create({ id: uuidv4(), userId, courseId, progress: 0, completedLessons: [] });
    }
    record.progress = dto.progress;
    return this.progressRepo.save(record);
  }

  async getCoursesWithProgress(userId: string) {
    const [courses, progressList] = await Promise.all([this.getCourses(), this.getUserProgress(userId)]);
    const progressMap = new Map(progressList.map(p => [p.courseId, p]));
    return courses.map(c => {
      const prog = progressMap.get(c.id);
      return { ...c, progress: prog?.progress ?? 0, completedLessons: prog?.completedLessons ?? [] };
    });
  }

  async saveQuizResult(userId: string, courseId: string, score: number, passed: boolean, correctCount: number, totalQuestions: number) {
    const course = await this.courseRepo.findOneBy({ id: courseId });
    if (!course) throw new NotFoundException('Curso no encontrado');

    const result = this.quizResultRepo.create({
      id: uuidv4(),
      userId,
      courseId,
      score,
      passed,
      correctCount,
      totalQuestions,
    });
    return this.quizResultRepo.save(result);
  }

  async getMyQuizResults(userId: string) {
    return this.quizResultRepo.find({
      where: { userId },
      relations: ['course'],
      order: { createdAt: 'DESC' },
    });
  }
}
